const headers = $input.first().json.headers || {};
const expectedToken = $env.TELEGRAM_WEBHOOK_SECRET;
if (!expectedToken) {
  throw new Error('TELEGRAM_WEBHOOK_SECRET is required');
}
const receivedToken = headers['x-telegram-bot-api-secret-token'] || headers['X-Telegram-Bot-Api-Secret-Token'] || '';
if (receivedToken && receivedToken === expectedToken) {
  return $input.all();
}
throw new Error('Invalid secret_token');

const body = $input.first().json.body || {};
const callback = body.callback_query || {};
const callbackMessage = callback.message || {};
const callbackChat = callbackMessage.chat || {};
const chatId = callbackChat.id ? String(callbackChat.id) : '';
const allowedChatId = $env.TELEGRAM_CHAT_ID || '';
if (!chatId || chatId !== allowedChatId) {
  throw new Error('Unauthorized chat_id: ' + chatId);
}

const data = String(callback.data || '').trim();
if (!data) {
  throw new Error('callback data is required');
}

if (data.startsWith('approval-resolve:')) {
  const parts = data.split(':');
  const approvalId = String(parts[1] || '').trim();
  const decisionRaw = String(parts[2] || '').trim().toLowerCase();
  const decision = decisionRaw === 'deny' ? 'reject' : decisionRaw;
  const reason = String(parts.slice(3).join(':') || 'telegram-callback').trim() || 'telegram-callback';
  return [{ json: {
    router_mode: 'approval_resolve',
    approval_action: 'approval-resolve',
    approval_id: approvalId,
    approval_decision: decision,
    approval_reason: reason,
    approval_by: 'telegram',
    schema_version: 1,
    source: 'n8n',
    type: 'telegram_approval',
    project_key: 'odin-core',
    title: 'Resolve Odin approval from Telegram',
    action_key: '',
    dedup_key: 'telegram_approval:' + approvalId + ':' + decision,
    requested_by: 'telegram',
    payload: {
      callback_query_id: String(callback.id || ''),
      chat_id: chatId,
      approval_id: approvalId,
      decision,
      reason,
      callback_data: data
    }
  } }];
}

return [{ json: {
  router_mode: 'intake',
  schema_version: 1,
  source: 'n8n',
  type: 'telegram_callback',
  project_key: 'odin-core',
  title: 'Handle Telegram callback: ' + data,
  action_key: '',
  dedup_key: 'telegram_callback:' + String(callback.id || Date.now()),
  requested_by: 'telegram',
  payload: {
    callback_query_id: String(callback.id || ''),
    chat_id: chatId,
    callback_data: data,
    message_id: String(callbackMessage.message_id || '')
  }
} }];

const body = $input.first().json.body || {};
const message = body.message || {};
const chat = message.chat || {};
const chatId = chat.id ? String(chat.id) : '';
const allowedChatId = $env.TELEGRAM_CHAT_ID || '';
if (!chatId || chatId !== allowedChatId) {
  throw new Error('Unauthorized chat_id: ' + chatId);
}

const text = String(message.text || '').trim();
if (!text.startsWith('/')) {
  return [];
}

const parts = text.split(/\s+/).filter(Boolean);
const command = (parts[0] || '').replace(/^\//, '');
const args = parts.slice(1);
return [{ json: {
  router_mode: 'intake',
  schema_version: 1,
  source: 'n8n',
  type: 'telegram_command',
  project_key: 'odin-core',
  title: 'Handle Telegram command: ' + command,
  action_key: '',
  dedup_key: 'telegram_command:' + String(message.message_id || Date.now()),
  requested_by: 'telegram',
  payload: {
    command,
    args,
    chat_id: chatId,
    message_id: String(message.message_id || ''),
    raw_message: body
  }
} }];
